import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './Profile.css';

const Profile = () => {
    const [user, setUser] = useState(null);
    const navigate = useNavigate();

    // Mock Watchlist Data (since backend doesn't provide it yet)
    const watchlist = [
        { id: 1, title: 'Money Heist', year: '2017', image: 'https://www.worthcrete.com/wp-content/uploads/2023/01/Money-Heist-Online-HINDI-WorthCrete.webp' },
        { id: 2, title: 'Wednesday', year: '2022', image: 'https://images.justwatch.com/poster/301078631/s718/wednesday.jpg' },
        { id: 3, title: 'Loki', year: '2021', image: 'https://images.thedirect.com/media/article_full/loki-season-2-mcu.jpg' },
        { id: 4, title: 'Stranger Things', year: '2016', image: 'https://static1.cbrimages.com/wordpress/wp-content/uploads/2024/09/stranger-things-every-seasons.jpg' },
        { id: 5, title: 'Mirzapur', year: '2018', image: 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEjnUs0fGX7ZYGytz947j19mBLMwaZMv_jCyZkXWwHMXt_GKRAhaclB0lmC5i_17U17x-G9Vqv3s-VkoXT5SvAuwZE-edTDZ7z3HTp-x6eHCwZ4N7UaPR_MWrO_yu76gbRSgODmfj_4XJU6C/s1200/mirzapur-2-1200-4.jpg' },
        { id: 6, title: 'Dark', year: '2017', image: 'https://www.irosf.com/wp-content/uploads/2020/12/dark-1.jpg' },
    ];

    useEffect(() => {
        const fetchProfile = async () => {
            const token = localStorage.getItem('token');
            if (!token) {
                navigate('/login');
                return;
            }
            try {
                // Simulate network delay for smooth animation
                setTimeout(() => {
                    const storedUser = localStorage.getItem('user');
                    if (storedUser) {
                        setUser(JSON.parse(storedUser));
                    } else {
                        // Fallback or fetch from API if needed
                        setUser({ username: 'Guest User', email: 'guest@example.com', createdAt: new Date().toISOString() });
                    }
                }, 800);
            } catch (error) {
                console.error("Profile fetch error", error);
                localStorage.removeItem('token');
                navigate('/login');
            }
        };
        fetchProfile();
    }, [navigate]);

    if (!user) return <div className="profile-page-wrapper">Loading...</div>;

    return (
        <div className="profile-page-wrapper">
            <div className="profile-content-container">

                {/* Left Side: Profile Card */}
                <div className="profile-card">
                    <div className="profile-avatar-container">
                        <div className="profile-avatar">
                            {user.username ? user.username.charAt(0).toUpperCase() : 'U'}
                        </div>
                    </div>

                    <div className="profile-details">
                        <h1 className="profile-name">{user.username}</h1>
                        <p className="profile-email">{user.email}</p>
                    </div>

                    <div className="profile-menu">
                        <div className="menu-item active">
                            <span>Overview</span>
                            <i className="fas fa-chart-pie"></i>
                        </div>
                        <div className="menu-item">
                            <span>Subscription</span>
                            <i className="fas fa-credit-card"></i>
                        </div>
                        <div className="menu-item">
                            <span>Settings</span>
                            <i className="fas fa-cog"></i>
                        </div>
                        <div
                            className="menu-item logout"
                            onClick={() => {
                                localStorage.removeItem('token');
                                navigate('/login');
                            }}
                        >
                            <span>Logout</span>
                            <i className="fas fa-sign-out-alt"></i>
                        </div>
                        <div
                            className="menu-item logout"
                            onClick={() => {
                                navigate('/');
                            }}
                        >
                            <span>Home</span>
                            <i className="fas fa-sign-out-alt"></i>
                        </div>
                    </div>
                </div>

                {/* Right Side: Watchlist */}
                <div className="watchlist-section">
                    <div className="watchlist-header">
                        <h2>My Watchlist</h2>
                        <span style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', marginLeft: 'auto' }}>See All</span>
                    </div>

                    <div className="watchlist-grid">
                        {watchlist.map((movie) => (
                            <div key={movie.id} className="watchlist-card">
                                <div className="card-image-wrapper">
                                    <img src={movie.image} alt={movie.title} />
                                    <div className="card-overlay">
                                        <h3 className="movie-title">{movie.title}</h3>
                                        <p className="movie-meta">{movie.year}</p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

            </div>
        </div>
    );
};

export default Profile;
